// ─── HELPERS ───
function getWeekNum(d){const diff=Math.floor((d-PLAN_START)/(864e5));return diff<0?-1:Math.floor(diff/7)+1;}
function getPhase(wk){
  if(wk<=4)return{name:"Foundation (Wk 1-4)",tip:"Learn form. RPE 6-7. Finish sets feeling you could do 3-4 more reps.",color:"var(--green)"};
  if(wk<=8)return{name:"Building (Wk 5-8)",tip:"Add weight when you hit top of rep range with good form. RPE 7-8.",color:"var(--blue)"};
  if(wk<=11)return{name:"Intensification (Wk 9-11)",tip:"Push toward PRs. RPE 8-9. Drop sets on isolation moves.",color:"var(--orange)"};
  return{name:"Deload (Wk 12)",tip:"All weights -40-50%. RPE 4-5. Planned recovery.",color:"var(--purple)"};
}
function getDayInfo(d){
  const wk=getWeekNum(d);if(wk<1||wk>12)return null;
  const dow=d.getDay(),wk_key=WORKOUT_MAP[dow];
  if(wk_key)return{type:'workout',key:wk_key,...WORKOUT_LABELS[wk_key],exercises:EXERCISES[wk_key],weekNum:wk,phase:getPhase(wk),isLegDay:LEG_DAYS.includes(wk_key)};
  if(REST_DAYS[dow])return{type:'recovery',...REST_DAYS[dow],weekNum:wk,phase:getPhase(wk)};
  return null;
}
function getCardio(type,wk){
  if(type.startsWith('push'))return wk%2===1?CARDIO_STEADY:CARDIO_PROGRESSIVE;
  return wk%2===1?CARDIO_INTERVALS:CARDIO_STEADY;
}
